class Solution:
    def numberOfSequence(self, n: int, sick: List[int]) -> int:
        MOD = 10**9 + 7
        k = len(sick)
        if k == 0:
            return 0
        if k == n:
            return 1

        # Precompute factorials and inverse factorials modulo MOD
        max_n = n
        fact = [1] * (max_n + 1)
        for i in range(1, max_n + 1):
            fact[i] = fact[i - 1] * i % MOD

        # Compute combinations C(n, k) = fact[n] * inv_fact[k] * inv_fact[n - k] % MOD
        def comb(n, k):
            if k < 0 or k > n:
                return 0
            return fact[n] * pow(fact[k], MOD - 2, MOD) * pow(fact[n - k], MOD - 2, MOD) % MOD

        res = 1
        prev = -1
        for i in range(len(sick)):
            start = sick[i]
            if prev != -1:
                gap = start - prev - 1
                if gap > 0:
                    res = res * comb(gap + 1, 1) % MOD
            prev = start

        # Handle the last segment
        last = n - 1
        gap = last - sick[-1]
        if gap > 0:
            res = res * comb(gap + 1, 1) % MOD

        return res
